+
+  // Host side kernel arguments
+  struct Arguments {
+    DTypeQ const* Q_ptr;
+    LayoutT layout_Q;
+    DTypeKV const* K_ptr;
+    LayoutT layout_K;
+    DTypeKV const* V_ptr;
+    LayoutT layout_V;
+    IdType const* kv_indices;
+    int window_left;
+    AdditionalParams additional_params;
+  };
+
+  // Device side kernel params
+  struct Params {
+    LayoutT layout_Q;
+    LayoutT layout_K;
+    LayoutT layout_V;
+    TMA_Q tma_load_Q;
+    DTypeKV* K_ptr;
+    DTypeKV* V_ptr;
+    IdType* kv_indices;
+    int window_left;
+    AdditionalParams additional_params;
+    using DTypeKV = typename Ktraits::DTypeKV;
+  };
